{
  "global": "Answer each of the seven developmental biology questions by synthesizing knowledge of Hox gene regulation, embryonic signaling pathways, experimental evidence from chick/mouse/fish developmental models, and comparative developmental anatomy across species.",
  "subtasks": [
    {
      "subtask": "Interpret the somatopleure rotation experiment and predict organizational outcome",
      "atomics": [
        "Explain what the somatopleure tissue contains (mesoderm + ectoderm layers)",
        "Identify the role of the mesoderm as an organizer/signaling center in HH11 stage",
        "Predict disruption to anterior-posterior organizer signaling",
        "Determine outcome based on loss of inductive gradient orientation"
      ]
    },
    {
      "subtask": "Trace cell lineages to earliest stages for forelimb, hindlimb, and interlimb with Hox genes",
      "atomics": [
        "Research earliest forelimb mesoderm specification stage and identify Tbx5 role",
        "Research earliest hindlimb mesoderm specification stage and identify Tbx4 role",
        "Identify interlimb region specification and marker genes (e.g., Pitx1 repression)",
        "Map HOXA and HOXD cluster genes responsible for digit identity specification",
        "Cross-reference published lineage tracing studies (Odom et al., Laufer et al.) for stage assignments"
      ]
    },
    {
      "subtask": "Analyze HOXB5 deletion phenotype in murine limb development",
      "atomics": [
        "Identify HOXB5 expression pattern during murine limb bud outgrowth and patterning",
        "Review knockout study phenotypes (e.g., digit transformations, skeletal fusions)",
        "Describe anterior-posterior axis effects and digit identity shifts",
        "Specify which skeletal elements are affected (carpals, tarsals, digits)"
      ]
    },
    {
      "subtask": "Predict limb patterning effects from CYP26A1 overexpression and RA treatment",
      "atomics": [
        "Explain CYP26A1's enzymatic function as a retinoic acid metabolizer",
        "Describe the RA gradient's role in establishing anterior-posterior polarity",
        "Predict anterior digit identity shifts from CYP26A1 overexpression (reduced RA)",
        "Predict posterior digit identity shifts and anterior digit loss from RA treatment",
        "Connect predictions to known RA dose-response relationships in limb patterning"
      ]
    },
    {
      "subtask": "Identify the limb patterning protein specifically targeted by HOX9 deletion at HH17",
      "atomics": [
        "Confirm which HOX9 paralogs are expressed in chick limb buds at HH17",
        "Research HOX9 transcriptional target genes in limb development",
        "Identify Sonic Hedgehog (SHH) as primary limb patterning output",
        "Confirm HOX9's role in regulating SHH expression in the zone of polarizing activity (ZPA)"
      ]
    },
    {
      "subtask": "Determine embryonic germ layer origin of fish median fins and evolutionary implications",
      "atomics": [
        "Research embryological origin of median fins (dorsal, caudal, anal) in fish",
        "Confirm mesodermal origin and compare to paired fin origin",
        "Identify shared developmental genes between median and paired fins (Hox clusters, Fgf signaling)",
        "Propose evolutionary hypothesis linking median and paired fin evolution through gene co-option"
      ]
    },
    {
      "subtask": "Compare developmental axes between median fins and paired appendages",
      "atomics": [
        "Define the three axes of development (anterior-posterior, dorsal-ventral, medial-lateral)",
        "Describe axis orientation and dominant morphogenetic gradients in paired appendages (limbs)",
        "Describe axis orientation and dominant morphogenetic gradients in median fins",
        "Identify key signaling differences (e.g., Wnt/Fgf gradient orientation)",
        "Explain how axis differences constrain skeletal organization and evolutionary outcomes"
      ]
    }
  ],
  "global_atomics": [
    "Verify all cited genes, stages, and phenotypes against primary literature",
    "Ensure consistency in model organism nomenclature (mouse/chick/fish Hox gene naming)",
    "Synthesize cross-species comparisons to support evolutionary developmental conclusions"
  ],
  "gold_actions": {
    "global": "Synthesize experimental evidence from chick, mouse, and fish developmental models to explain Hox-regulated limb patterning, organizer signaling, retinoic acid gradients, and fin evolution through systematic analysis of embryonic induction, cell lineage specification, gene deletion phenotypes, and comparative developmental anatomy.",
    "subtasks": [
      {
        "subtask": "Predict somatopleure rotation outcome as disruption to mesoderm-ectoderm signaling axis",
        "atomics": [
          "Identify somatopleure as source of organizing signals to neural plate",
          "Predict loss of anterior-posterior gradient orientation upon rotation",
          "Conclude likely outcome of duplicated, inverted, or mirror-image structures"
        ]
      },
      {
        "subtask": "Identify cell lineage specification stages with specific Hox genes for each limb region",
        "atomics": [
          "Identify forelimb specification at HH9-HH10 with Tbx5 as master regulator",
          "Identify hindlimb specification at HH10-HH11 with Tbx4 as master regulator",
          "Identify interlimb suppression via repression of Tbx genes by Pitx1",
          "Map HOXA9-13 and HOXD9-13 paralogs to digit identity (D1-D5)"
        ]
      },
      {
        "subtask": "Describe HOXB5 deletion causing posterior digit identity transformations and skeletal defects",
        "atomics": [
          "Report posterior limb element reductions and anterior identity expansions",
          "Document digit transformations (polydactyly or digit identity shifts)",
          "Specify carpal/tarsal disruptions and possible bone fusions"
        ]
      },
      {
        "subtask": "Predict CYP26A1 overexpression shifts anterior digit identity; RA treatment shifts posterior",
        "atomics": [
          "Conclude CYP26A1 overexpression reduces RA levels, moving digits anterior (loss of posterior digits)",
          "Conclude RA treatment increases RA levels, moving digits posterior (loss of anterior digits)",
          "Note dose-dependent transformation of digit identities along anterior-posterior axis"
        ]
      },
      {
        "subtask": "Identify Sonic Hedgehog as the HOX9-regulated limb patterning protein at HH17",
        "atomics": [
          "Confirm HOXA9/D9 expression in ZPA at HH17 chick",
          "Identify SHH as direct transcriptional target of HOX9 proteins",
          "Note SHH centrality to anterior-posterior patterning and digit specification"
        ]
      },
      {
        "subtask": "Confirm mesodermal origin of fish median fins and propose evolutionary continuity with paired fins",
        "atomics": [
          "Cite embryological evidence for shared mesodermal origin",
          "Note shared Hox gene expression (HOXA-D clusters) in both median and paired fins",
          "Propose evolutionary model of paired-fin-to-fin duplication and axis reorganization"
        ]
      },
      {
        "subtask": "Compare developmental axes: paired appendages dominated by anterior-posterior; median fins by medial-lateral",
        "atomics": [
          "Note anterior-posterior axis as primary patterning axis in paired limbs (Hox gene collinearity)",
          "Note medial-lateral axis dominance in median fin development (dorsal-ventral positioning along body)",
          "Identify different dominant signaling gradients (Wnt/Fgf orientation)",
          "Conclude axis difference explains skeletal diversity (digits vs fin rays) and evolutionary constraints"
        ]
      }
    ],
    "global_atomics": [
      "Cross-validate staging nomenclature (HH = Hamburger-Hamilton for chick; verify equivalents for mouse)",
      "Confirm Hox gene paralogy assignments across species using current gene nomenclature",
      "Integrate experimental evidence (knockout/overexpression studies) with evolutionary developmental hypotheses"
    ]
  }
}
```
